def longest_common_subsequence(s1, s2):
    m = len(s1)
    n = len(s2)
    dp = [[0] * (n+1) for _ in range(m+1)]

    # initialize matrix
    for i in range(1, m+1):
        if s1[i-1] == s2[0]:
            dp[i][0] = 1 + dp[i-1][0]
        else:
            dp[i][0] = 0

    for j in range(1, n+1):
        if s1[m-j] == s2[j-1]:
            dp[m][j] = dp[m-j][j-1] + 1
        else:
            dp[m][j] = 0

    # backtrack to find the longest common subsequence
    LCS = []
    i = m
    j = n
    while i>0 and j>0:
        if s1[i-1] == s2[j-1]:
            LCS.append(s1[i-1])
            i -= 1
            j -= 1
        elif dp[i-1][j] > dp[i][j-1]:
            i -= 1
        else:
            j -= 1

    LCS.reverse()
    return LCS
